mapper.update:
UPDATE knowledge_base
question = #{question}, answer = #{answer}, tags = #{tags}, source = #{source}, usage_count = #{usageCount}, status = #{status}, quality_score = #{qualityScore},
WHERE id = #{id}

mapper.select:
SELECT * FROM knowledge_base
WHERE status = 1 AND quality_score >= #{minScore}
ORDER BY quality_score DESC, usage_count DESC

SELECT * FROM knowledge_base
ORDER BY created_at DESC
LIMIT #{offset}, #{limit}
